/*! 
 * @brief fec_cl91 
 */ 
#define PHYMOD_FEC_CL91 0x10000 /**< enable/disable FEC cl91 */

#define PHYMOD_FEC_CL91_SET(enable) (enable |= PHYMOD_FEC_CL91)

#define PHYMOD_FEC_CL91_CLR(enable) (enable &= ~PHYMOD_FEC_CL91)

#define PHYMOD_FEC_CL91_GET(enable) (enable & PHYMOD_FEC_CL91 ? 1 : 0)

/*! 
 * @brief fec_cl108 
 */ 
#define PHYMOD_FEC_CL108 0x20000 /**< enable/disable FEC cl108 */

#define PHYMOD_FEC_CL108_SET(enable) (enable |= PHYMOD_FEC_CL108)

#define PHYMOD_FEC_CL108_CLR(enable) (enable &= ~PHYMOD_FEC_CL108)

#define PHYMOD_FEC_CL108_GET(enable) (enable & PHYMOD_FEC_CL108 ? 1 : 0)

