/*!
 * @struct plp_barchetta_phymod_autoneg_ability_s
 * @brief autoneg_ability 
 */ 
typedef struct plp_barchetta_phymod_autoneg_ability_s {
    uint32_t an_cap; /**< This indicates the CL73 capability. For instance, CL73 40G KR4 */
    uint32_t an_cap_ext; /**< This indicates the CL73 capability. For instance, CL73 40G KR4 */
    uint32_t cl73bam_cap; /**< This indicates the CL73 BAM capability. For instance, CL73 BAM 20G KR2 */
    uint32_t cl37bam_cap; /**< This indicates the CL37 BAM capability. For instance, CL37 BAM 5G X4 */
    uint32_t an_fec; /**< Whether to enable CL74 FEC or not */
    uint32_t an_cl72; /**< Whether CL72 should be turned on when system is in AN mode. Default value is 1 */
    uint32_t an_hg2; /**< Whether HG2 mode should be enabled during AN mode */
    uint32_t capabilities; /**< AN capabilities, such as CL37, CL73, CL37BAM, etc */
    uint32_t speed_full_duplex; /**< Speed capabilities for full duplex */
    uint32_t speed_half_duplex; /**< Speed capabilities for half duplex */
    uint32_t eee; /**< EEE capabilities */
    uint32_t pause; /**< Pause capabilities */
    plp_barchetta_phymod_cl37_sgmii_speed_t sgmii_speed;
    uint32_t an_master_lane; /**< Master lane belongs to port. For 10 lane port[0-9], for 4 lane port [0-3], for 2 lane port [0-1]. This paramter is ignored for single lane port */
    uint32_t speed_2pair; /**< Speed capabilities for 2-pair ethernet mode */
} plp_barchetta_phymod_autoneg_ability_t;

/* plp_barchetta_phymod_autoneg_ability_t initialization and validation */
int plp_barchetta_phymod_autoneg_ability_t_validate(const plp_barchetta_phymod_autoneg_ability_t* phymod_autoneg_ability);
int plp_barchetta_phymod_autoneg_ability_t_init(plp_barchetta_phymod_autoneg_ability_t* phymod_autoneg_ability);

