#define PHYMOD_BASET_INTR_PTP_PIC 0x1
#define PHYMOD_BASET_INTR_PTP_FSYNC 0x2
#define PHYMOD_BASET_INTR_PTP_SOP 0x4
#define PHYMOD_BASET_INTR_PTP_SYNCIN 0x8
#define PHYMOD_BASET_INTR_PTP_IPG 0x10

#define PHYMOD_BASET_INTR_PTP_PIC_SET(baset_intr) (baset_intr |= PHYMOD_BASET_INTR_PTP_PIC)
#define PHYMOD_BASET_INTR_PTP_FSYNC_SET(baset_intr) (baset_intr |= PHYMOD_BASET_INTR_PTP_FSYNC)
#define PHYMOD_BASET_INTR_PTP_SOP_SET(baset_intr) (baset_intr |= PHYMOD_BASET_INTR_PTP_SOP)
#define PHYMOD_BASET_INTR_PTP_SYNCIN_SET(baset_intr) (baset_intr |= PHYMOD_BASET_INTR_PTP_SYNCIN)
#define PHYMOD_BASET_INTR_PTP_IPG_SET(baset_intr) (baset_intr |= PHYMOD_BASET_INTR_PTP_IPG)

#define PHYMOD_BASET_INTR_PTP_PIC_CLR(baset_intr) (baset_intr &= ~PHYMOD_BASET_INTR_PTP_PIC)
#define PHYMOD_BASET_INTR_PTP_FSYNC_CLR(baset_intr) (baset_intr &= ~PHYMOD_BASET_INTR_PTP_FSYNC)
#define PHYMOD_BASET_INTR_PTP_SOP_CLR(baset_intr) (baset_intr &= ~PHYMOD_BASET_INTR_PTP_SOP)
#define PHYMOD_BASET_INTR_PTP_SYNCIN_CLR(baset_intr) (baset_intr &= ~PHYMOD_BASET_INTR_PTP_SYNCIN)
#define PHYMOD_BASET_INTR_PTP_IPG_CLR(baset_intr) (baset_intr &= ~PHYMOD_BASET_INTR_PTP_IPG)

#define PHYMOD_BASET_INTR_PTP_PIC_GET(baset_intr) (baset_intr & PHYMOD_BASET_INTR_PTP_PIC ? 1 : 0)
#define PHYMOD_BASET_INTR_PTP_FSYNC_GET(baset_intr) (baset_intr & PHYMOD_BASET_INTR_PTP_FSYNC ? 1 : 0)
#define PHYMOD_BASET_INTR_PTP_SOP_GET(baset_intr) (baset_intr & PHYMOD_BASET_INTR_PTP_SOP ? 1 : 0)
#define PHYMOD_BASET_INTR_PTP_SYNCIN_GET(baset_intr) (baset_intr & PHYMOD_BASET_INTR_PTP_SYNCIN ? 1 : 0)
#define PHYMOD_BASET_INTR_PTP_IPG_GET(baset_intr) (baset_intr & PHYMOD_BASET_INTR_PTP_IPG ? 1 : 0)

#define PHYMOD_PKT_TYPE_ALL 0x1
#define PHYMOD_PKT_TYPE_CRC 0x10
#define PHYMOD_PKT_TYPE_PTP_SYNC 0x100
#define PHYMOD_PKT_TYPE_PTP_DELAYREQ 0x200
#define PHYMOD_PKT_TYPE_PTP_PDELAYREQ 0x400
#define PHYMOD_PKT_TYPE_PTP_PDELAYRESP 0x800

#define PHYMOD_PKT_TYPE_ALL_SET(pkt_type) (pkt_type |= PHYMOD_PKT_TYPE_ALL)
#define PHYMOD_PKT_TYPE_CRC_SET(pkt_type) (pkt_type |= PHYMOD_PKT_TYPE_CRC)
#define PHYMOD_PKT_TYPE_PTP_SYNC_SET(pkt_type) (pkt_type |= PHYMOD_PKT_TYPE_PTP_SYNC)
