    unsigned short ieee_fecpcs_alignment_status_3; /**< 3.52 - align_status @0..7 for 200g only */
    unsigned short ieee_fecpcs_lane_mapping[8]; /**< 3.400..3.407 - pcs lane mapping [4:0]; for 200g only */
