/*!
 * @enum phymod_srds_diag_access_e
 * @brief Configures the type of access needed. 
 */ 
typedef enum phymod_srds_diag_access_e {
    phymodSrdsRegRead = 0x0, /**< Register Read (param becomes count). */
    phymodSrdsRegRmw = 0x1, /**< Register Read-Modify-Write (param becomes mask). */
    phymodSrdsCoreRamRdByte = 0x2, /**< CORE RAM Read byte  (data becomes count). */
    phymodSrdsCoreRamRmwByte = 0x3, /**< CORE RAM Read-Modify-Write byte (param becomes mask). */
    phymodSrdsCoreRamRdWord = 0x4, /**< CORE RAM Read word  (data becomes count). */
    phymodSrdsCoreRamRmwWord = 0x5, /**< CORE RAM Read-Modify-Write word (param becomes mask). */
    phymodSrdsLaneRamRdByte = 0x6, /**< LANE RAM Read byte    (data becomes count). */
    phymodSrdsLaneRamRmwByte = 0x7, /**< LANE RAM Read-Modify-Write byte (param becomes mask). */
    phymodSrdsLaneRamRdWord = 0x8, /**< LANE RAM Read word  (data becomes count). */
    phymodSrdsLaneRamRmwWord = 0x9, /**< LANE RAM Read-Modify-Write word (param becomes mask). */
    phymodSrdsGlobRamRdByte = 0xa, /**< Global RAM Read byte  (data becomes count). */
    phymodSrdsGlobRamRmwByte = 0xb, /**< Global RAM Read-Modify-Write byte(param becomes mask). */
    phymodSrdsGlobRamRdWord = 0xc, /**< Global RAM Read word  (data becomes count). */
    phymodSrdsGlobRamRmwWord = 0xd, /**< Global RAM Read-Modify-Write word (param becomes mask). */
    phymodSrdsProgRamRdByte = 0xe, /**< Prog RAM Read byte (data becomes count). */
    phymodSrdsProgRamRdWord = 0xf, /**< Prog RAM Read word (data becomes count). */
    phymodSrdsUcCmd = 0x10, /**< uC Command (addr becomes command; param becomes supp_info). */
    phymodSrdsCount
} phymod_srds_diag_access_t;

#ifdef PHYMOD_DIAG
extern plp_barchetta_enum_mapping_t phymod_srds_diag_access_t_mapping[];
#endif /*PHYMOD_DIAG*/

/* phymod_srds_diag_access_t validation */
int plp_barchetta_phymod_srds_diag_access_t_validate(phymod_srds_diag_access_t phymod_srds_diag_access);
typedef struct phymod_srds_diag_access_cfg_s {
    uint16_t addr; /**< In most cases is the address of the register or RAM location. */
    uint16_t data; /**< In most cases is the data to be written. */
    uint16_t param; /**< It is a multipurpose parameter which can be a mask or other data. */
    phymod_srds_diag_access_t access_type; /**< Controls the type of access requested for diagnostics purposes. */
} phymod_srds_diag_access_cfg_t;

/* phymod_srds_diag_access_cfg_t initialization and validation */
int plp_barchetta_phymod_srds_diag_access_cfg_t_validate(const phymod_srds_diag_access_cfg_t* phymod_srds_diag_access_cfg);
int plp_barchetta_phymod_srds_diag_access_cfg_t_init(phymod_srds_diag_access_cfg_t* phymod_srds_diag_access_cfg);

